// Heap: objects
Object obj = new Object(); // heap

// Stack: local variables
void method() {
    int x = 5;        // stack frame
    String s = "hi";  // reference on stack, object on heap
}

// Metaspace: class data
class MyClass {           // class definition in metaspace
    static int count = 0; // static field in metaspace
}

// GC roots keep objects alive
static Object staticRef;    // GC root (static field)
void method() {
    Object local = new Object(); // GC root (stack)
    // When method returns, local is no longer a root
    // Object becomes eligible for GC if no other refs
}
// Circular references ARE collected — GC uses reachability, not ref counting

