// Comparable — natural order
class Employee implements Comparable<Employee> {
    int salary;
    public int compareTo(Employee o) { return Integer.compare(salary, o.salary); }
}

// Comparator — flexible, external
Comparator<Employee> byName = Comparator.comparing(e -> e.name);
Comparator<Employee> byNameThenSalary = Comparator
    .comparing((Employee e) -> e.name)
    .thenComparingInt(e -> e.salary);
list.sort(byNameThenSalary);

List<String> list = new ArrayList<>(List.of("a","b","c"));
ListIterator<String> it = list.listIterator();
while (it.hasNext()) {
    String s = it.next();
    it.set(s.toUpperCase()); // replace during iteration
}
// Backwards
while (it.hasPrevious()) System.out.print(it.previous()); // C B A

// Fail-fast — throws CME
List<String> list = new ArrayList<>(List.of("a","b"));
for (String s : list) {
    list.remove(s); // ConcurrentModificationException!
}
// Safe removal
Iterator<String> it = list.iterator();
while (it.hasNext()) { it.next(); it.remove(); } // ok

// Fail-safe
List<String> safe = new CopyOnWriteArrayList<>(list);
for (String s : safe) { safe.remove(s); } // no exception

